## 三、修复后的代码片段

替换你当前页面里的这一整段：

```html
<script>
 // 客服随机选择与本地存储逻辑
 (function() {
 ...
 })();
</script>
```

为下面版本：

```html
<script>
 (function () {
 function showCopySuccess() {
 if (window.showCopySuccessPopup) {
 window.showCopySuccessPopup();
 } else {
 alert('微信复制成功，快去添加好友吧！');
 }
 }

 function showCopyFailed() {
 alert('复制失败，请手动复制微信号');
 }

 function escapeHtml(str) {
 return String(str || '')
 .replace(/&/g, '&amp;')
 .replace(/</g, '&lt;')
 .replace(/>/g, '&gt;')
 .replace(/"/g, '&quot;')
 .replace(/'/g, '&#39;');
 }

 function parseServiceList(rawValue) {
 if (!rawValue) return [];

 try {
 if (Array.isArray(rawValue)) {
 return rawValue;
 }

 if (typeof rawValue === 'string') {
 const trimmed = rawValue.trim();
 if (!trimmed) return [];

 const parsed = JSON.parse(trimmed);
 return Array.isArray(parsed) ? parsed : [];
 }

 return [];
 } catch (e) {
 console.error('客服列表解析失败', e, rawValue);
 return [];
 }
 }

 function normalizeService(item) {
 if (!item || typeof item !== 'object') return null;

 return {
 nickname: item.nickname ? String(item.nickname) : '',
 wechat: item.wechat ? String(item.wechat) : '',
 mobile: item.mobile ? String(item.mobile) : ''
 };
 }

 function getRandomService(list) {
 if (!Array.isArray(list) || list.length === 0) {
 return { nickname: '', wechat: '', mobile: '' };
 }
 return list[Math.floor(Math.random() * list.length)];
 }

 function isServiceValid(service, list) {
 if (!service || !service.wechat) return false;
 return list.some(function (item) {
 return item.wechat === service.wechat;
 });
 }

 // 注意：这里要求后端输出的是合法 JSON
 // 推荐后端直接输出 JSON 数组，如:
 // [{"nickname":"A","wechat":"wx001","mobile":"138..."}]
 const rawServiceList = {{.ServiceListJSON}};

 let serviceList = parseServiceList(rawServiceList)
 .map(normalizeService)
 .filter(function (item) {
 return item && item.wechat;
 });

 let currentService = {
 nickname: '',
 wechat: '',
 mobile: ''
 };

 if (serviceList.length > 0) {
 const storageKey = 'promotion_service_' + window.location.pathname;
 const savedService = localStorage.getItem(storageKey);

 if (savedService) {
 try {
 const parsed = normalizeService(JSON.parse(savedService));
 if (parsed && isServiceValid(parsed, serviceList)) {
 currentService = parsed;
 } else {
 currentService = getRandomService(serviceList);
 localStorage.setItem(storageKey, JSON.stringify(currentService));
 }
 } catch (e) {
 currentService = getRandomService(serviceList);
 localStorage.setItem(storageKey, JSON.stringify(currentService));
 }
 } else {
 currentService = getRandomService(serviceList);
 localStorage.setItem(storageKey, JSON.stringify(currentService));
 }
 }

 window.currentService = currentService;

 window.copyWechatGlobal = function (wechat) {
 const copyWechat = (wechat || window.currentService?.wechat || '').trim();

 if (!copyWechat) {
 alert('当前暂无可复制的微信号');
 return;
 }

 if (navigator.clipboard && window.isSecureContext) {
 navigator.clipboard.writeText(copyWechat).then(function () {
 showCopySuccess();
 }).catch(function () {
 fallbackCopy(copyWechat);
 });
 } else {
 fallbackCopy(copyWechat);
 }
 };

 function fallbackCopy(text) {
 try {
 const input = document.createElement('input');
 input.value = text;
 input.setAttribute('readonly', 'readonly');
 input.style.position = 'fixed';
 input.style.left = '-9999px';
 document.body.appendChild(input);
 input.select();
 input.setSelectionRange(0, input.value.length);

 const success = document.execCommand('copy');
 document.body.removeChild(input);

 if (success) {
 showCopySuccess();
 } else {
 showCopyFailed();
 }
 } catch (e) {
 console.error('fallbackCopy 失败', e);
 showCopyFailed();
 }
 }

 window.addCount = function (el) {
 if (!el) return;
 const match = el.textContent.match(/\d+/);
 if (match) {
 const current = parseInt(match[0], 10) || 0;
 el.textContent = el.textContent.replace(/\d+/, String(current + 1));
 }
 };

 document.addEventListener('DOMContentLoaded', function () {
 const displayWechat = currentService.wechat || '';
 const displayNickname = currentService.nickname || '';

 document.querySelectorAll('.ql-editor-content').forEach(function (el) {
 if (!el.innerHTML || el.innerHTML.indexOf('##客服昵称##') === -1) {
 return;
 }

 let displayText = escapeHtml(displayWechat);
 if (displayNickname) {
 displayText =
 escapeHtml(displayNickname) +
 '（微信：' +
 escapeHtml(displayWechat) +
 '）';
 }

 const wechatHtml =
 '<span class="wechat-clickable" onclick="copyWechatGlobal()" style="cursor:pointer;">' +
 displayText +
 '</span>';

 el.innerHTML = el.innerHTML.replace(/##客服昵称##/g, wechatHtml);
 });

 document.querySelectorAll('.wechat').forEach(function (el) {
 el.textContent = currentService.wechat || '';
 });

 document.querySelectorAll('.phone').forEach(function (el) {
 el.textContent = currentService.mobile || '';
 });
 });
 })();
</script>
```

