 window.currentService = currentService;

 window.copyWechatGlobal = function (wechat) {
 const copyWechat = (wechat || window.currentService?.wechat || '').trim();

 if (!copyWechat) {
 alert('当前暂无可复制的微信号');
 return;
 }

 if (navigator.clipboard && window.isSecureContext) {
 navigator.clipboard.writeText(copyWechat).then(function () {
 showCopySuccess();
 }).catch(function () {
 fallbackCopy(copyWechat);
 });
 } else {
 fallbackCopy(copyWechat);
 }
 };

 function fallbackCopy(text) {
 try {
 const input = document.createElement('input');
 input.value = text;
 input.setAttribute('readonly', 'readonly');
 input.style.position = 'fixed';
 input.style.left = '-9999px';
 document.body.appendChild(input);
 input.select();
 input.setSelectionRange(0, input.value.length);

 const success = document.execCommand('copy');
 document.body.removeChild(input);

 if (success) {
 showCopySuccess();
 } else {
 showCopyFailed();
 }
 } catch (e) {
 console.error('fallbackCopy 失败', e);
 showCopyFailed();
 }
 }

 window.addCount = function (el) {
 if (!el) return;
 const match = el.textContent.match(/\d+/);
 if (match) {
 const current = parseInt(match[0], 10) || 0;
 el.textContent = el.textContent.replace(/\d+/, String(current + 1));
 }
 };

 document.addEventListener('DOMContentLoaded', function () {
 const displayWechat = currentService.wechat || '';
 const displayNickname = currentService.nickname || '';

 document.querySelectorAll('.ql-editor-content').forEach(function (el) {
 if (!el.innerHTML || el.innerHTML.indexOf('##客服昵称##') === -1) {
 return;
 }

 let displayText = escapeHtml(displayWechat);
 if (displayNickname) {
 displayText =
 escapeHtml(displayNickname) +
 '（微信：' +
 escapeHtml(displayWechat) +
 '）';
 }

 const wechatHtml =
 '<span class="wechat-clickable" onclick="copyWechatGlobal()" style="cursor:pointer;">' +
 displayText +
 '</span>';

 el.innerHTML = el.innerHTML.replace(/##客服昵称##/g, wechatHtml);
 });

 document.querySelectorAll('.wechat').forEach(function (el) {
 el.textContent = currentService.wechat || '';
 });

 document.querySelectorAll('.phone').forEach(function (el) {
 el.textContent = currentService.mobile || '';
 });
 });
 })();
</script>
```

